### Submit Billing Data with Vercel SDK

Source: https://vercel.com/docs/rest-api/sdk/marketplace/submit-billing-data

Initialize the Vercel SDK with a bearer token and submit billing data including pricing, quantities, and usage metrics for a marketplace integration. Requires a valid integrationConfigurationId and properly formatted billing and usage arrays.

```typescript
import { Vercel } from "@vercel/sdk";


const vercel = new Vercel({
  bearerToken: "<YOUR_BEARER_TOKEN_HERE>",
});


async function run() {
  await vercel.marketplace.submitBillingData({
    integrationConfigurationId: "<id>",
    requestBody: {
      timestamp: new Date("2023-11-26T05:03:03.977Z"),
      eod: new Date("2023-04-14T04:58:49.647Z"),
      period: {
        start: new Date("2023-03-12T13:32:00.895Z"),
        end: new Date("2023-12-15T15:17:13.187Z"),
      },
      billing: [
        {
          billingPlanId: "<id>",
          name: "<value>",
          price: "694.00",
          quantity: 228.64,
          units: "<value>",
          total: "<value>",
        },
        {
          billingPlanId: "<id>",
          name: "<value>",
          price: "694.00",
          quantity: 228.64,
          units: "<value>",
          total: "<value>",
        },
      ],
      usage: [
        {
          name: "<value>",
          type: "interval",
          units: "<value>",
          dayValue: 5212.43,
          periodValue: 4147.35,
        },
        {
          name: "<value>",
          type: "interval",
          units: "<value>",
          dayValue: 5212.43,
          periodValue: 4147.35,
        },
        {
          name: "<value>",
          type: "interval",
          units: "<value>",
          dayValue: 5212.43,
          periodValue: 4147.35,
        },
      ],
    },
  });


}


run();
```

